 43→export const getFormattedPointsValue = (
 44→  amount: number,
 45→  type: TransactionType,
 46→): string => {
 47→  const prefix = type === 'CREDIT' || type === 'REFUNDED' ? '+ ' : '- ';
 48→  const label = Math.abs(amount) === 1 ? 'ponto' : 'pontos';
 49→  return `${prefix}${Math.abs(amount).toLocaleString('pt-BR')} ${label}`;
 50→};
